rss_url &lt;- "https://news.google.com/rss/search?q=(\"DWI\"%20OR%20\"drunk%20driving\"%20OR%20\"impaired%20driving\")%20\"El%20Paso\"&hl=en-US&gl=US&ceid=US:en"

rss_items &lt;- tidyfeed(rss_url) %&gt;%
  select(item_title, item_link, item_pub_date) %&gt;%
  slice_head(n = 100)

GET request successful. Parsing...

clean_title &lt;- function(x) {
  parts &lt;- str_split(x, " - ", simplify = TRUE)

  if (ncol(parts) &gt; 1) {
    list(title = parts[,1], source = toupper(parts[,ncol(parts)]))
  } else {
    list(title = x, source = "UNKNOWN")
  }
}

format_date &lt;- function(x) {
  format(as.Date(x), "%B %d, %Y")
}

get_tags &lt;- function(text) {
  tags &lt;- c()

  if (str_detect(text, regex("dwi|dui|drunk|impaired", TRUE))) tags &lt;- c(tags, "DWI")
  if (str_detect(text, regex("crash|accident|collision", TRUE))) tags &lt;- c(tags, "Crash")
  if (str_detect(text, regex("policy|law|bill", TRUE))) tags &lt;- c(tags, "Policy")
  if (str_detect(text, regex("arrest|charged", TRUE))) tags &lt;- c(tags, "Arrest")
  if (str_detect(text, regex("court|trial", TRUE))) tags &lt;- c(tags, "Court")
  if (str_detect(text, regex("legislation", TRUE))) tags &lt;- c(tags, "Legislation")
  if (str_detect(text, regex("enforcement", TRUE))) tags &lt;- c(tags, "Enforcement")
  if (str_detect(text, regex("alcohol", TRUE))) tags &lt;- c(tags, "Alcohol")
  if (str_detect(text, regex("traffic", TRUE))) tags &lt;- c(tags, "Traffic")
  if (str_detect(text, regex("injury", TRUE))) tags &lt;- c(tags, "Injury")
  if (str_detect(text, regex("fatal", TRUE))) tags &lt;- c(tags, "Fatality")
  if (str_detect(text, regex("police", TRUE))) tags &lt;- c(tags, "Police")
  if (str_detect(text, regex("texas", TRUE))) tags &lt;- c(tags, "Texas")
  if (str_detect(text, regex("el paso", TRUE))) tags &lt;- c(tags, "ElPaso")

  if (length(tags) == 0) tags &lt;- "General"
  paste(tags, collapse = ",")
}

for (i in 1:nrow(rss_items)) {

  p &lt;- clean_title(rss_items$item_title[i])
  tags &lt;- get_tags(rss_items$item_title[i])

  cat(
    paste0(
      "&lt;div class='news-card' data-tags='", tags, "' style='
        padding:16px;
        border-radius:12px;
        background:#fff3d6;
        border:1px solid #e5e7eb;
        position:relative;
      '&gt;",

      "&lt;div style='position:absolute; top:10px; right:12px; font-size:0.75em; color:#888;'&gt;",
      format_date(rss_items$item_pub_date[i]),
      "&lt;/div&gt;",

      "&lt;div style='font-size:0.75em; font-weight:700; color:#7a2e1d; margin-bottom:6px;'&gt;",
      p$source,
      "&lt;/div&gt;",

      "&lt;a href='", rss_items$item_link[i], "' target='_blank' style='
        font-size:1.05em;
        font-weight:600;
        color:#5c1f14;
        text-decoration:none;
      '&gt;",
      p$title,
      "&lt;/a&gt;",

      "&lt;/div&gt;"
    )
  )
}

